        foreach ($templates as $data) {
            $data['model'] = $this->modelForType($data['type']);

            $template = AgentTemplate::firstOrNew([
                'company_id' => null,
                'name' => $data['name'],
            ]);

            $template->fill($template->exists ? ['model' => $data['model']] : $data);
            $template->save();
        }
