    private function modelForType(string $type): string
    {
        return match ($type) {
            'content_bg', 'seo_writer', 'newsletter_writer', 'report_writer',
            'email_composer', 'ad_copywriter', 'offer_builder', 'caption_writer',
            'hook_writer', 'faq_generator', 'meta_generator', 'summarizer',
            'translator', 'bg_text_corrector',
            // New content agents
            'story_writer', 'video_script_writer', 'calendar_planner',
            'ab_test_generator', 'whatsapp_message_writer', 'podcast_outline',
            'review_responder', 'chatbot_responder', 'crm_note_writer',
            'survey_builder', 'testimonial_extractor', 'product_describer',
            'invoice_generator', 'press_release_writer', 'event_planner',
            'telegram_bot_responder', 'email_sequence_writer' => 's_emanuilov/BgGPT-v1.0:9b',
            'qa_verifier' => 's_emanuilov/BgGPT-v1.0:2.6b',
            'analyzer', 'decision', 'swot_builder', 'sentiment_analyzer',
            'classifier', 'review_analyzer', 'researcher', 'trend_researcher',
            'competitor_profiler', 'people_researcher', 'document_ocr',
            // New analysis agents
            'brand_voice_checker', 'lead_scorer', 'price_optimizer',
            'customer_segmenter', 'persona_builder', 'budget_analyzer',
            'influencer_finder' => 'qwen2.5:14b',
            'keyword_extractor', 'hashtag_generator', 'data_extractor',
            'formatter', 'google_sheets_writer', 'email', 'webhook_sender',
            'slack_notifier', 'content_en',
            // New integration agents
            'airtable_writer' => 'qwen2.5:7b',
            'image_describer' => 'qwen2.5vl:7b',
            'image_prompt' => 'mistral',
            'human_approval' => '', // pauses the run — no LLM involved
            default => 'gemma4:12b',
        };
    }
